def binary_search(arr, target):
    left, right = 0, len(arr) - 1

    while left <= right:
        # Calculate mid to prevent potential overflow (though less critical in Python)
        mid = left + (right - left) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            # Target is in the right half
            left = mid + 1
        else: # arr[mid] > target
            # Target is in the left half
            right = mid - 1
